#include <stdio.h>

const char* classify(int age) {
    if (age >= 0 && age <= 12) return "Child";
    else if (age >= 13 && age <= 19) return "Teenager";
    else if (age >= 20 && age <= 64) return "Adult";
    else return "Senior";
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int age;
        scanf("%d", &age);
        printf("%s\n", classify(age));
    }
    return 0;
}

